const CACHE="beetlebot-v1",FILES=["/","/index.html","/bundle.js","/styles.css"];self.addEventListener("install",e=>{e.waitUntil(caches.open(CACHE).then(e=>e.addAll(FILES))),self.skipWaiting()}),self.addEventListener("fetch",e=>{e.respondWith(caches.match(e.request).then(t=>t||fetch(e.request)))}),self.addEventListener("activate",e=>{e.waitUntil(caches.keys().then(e=>Promise.all(e.filter(e=>e!==CACHE).map(e=>caches.delete(e))))),self.clients.claim()});